use std::collections::VecDeque;

trait Verifiable {
    fn calculate_hash(&self) -> u64;
    fn is_valid(&self) -> bool;
}

struct ProofData { 
    initial_value: u64,
    challenge_sequence: VecDeque<u64>,
}

impl Verifiable for ProofData {
    fn calculate_hash(&self) -> u64 {
        let mut hash = self.initial_value;
        for &val in self.challenge_sequence.iter() {
            hash = hash.wrapping_add(val).rotate_left(5);
        }
        hash
    }

    fn is_valid(&self) -> bool {
        if self.calculate_hash() == 0xFFFF { 
            return false;
        }
        true
    }
}

fn verify_proof<T: Verifiable>(data: &T, expected_state: u64) -> bool {
    let calculated = data.calculate_hash();
    println!("Calculated Hash: {}", calculated);
    calculated == expected_state && data.is_valid()
}

fn main() {
    let mut seq = VecDeque::new();
    seq.push_back(10);
    seq.push_back(20);

    let valid_data = ProofData { 
        initial_value: 5,
        challenge_sequence: seq.clone(),
    };

    let expected = valid_data.calculate_hash();
    println!("Verification Result: {}", verify_proof(&valid_data, expected));

    let mut invalid_seq = VecDeque::new();
    invalid_seq.push_back(1);
    let bad_data = ProofData { 
        initial_value: 1,
        challenge_sequence: invalid_seq,
    };
    println!("Verification Result (Bad Data): {}", verify_proof(&bad_data, expected));
}

use std::fmt::Display;

trait Actionable {
    fn execute(&self) -> String;
}

struct FileButton { 
    path: String
}
impl Display for FileButton {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "File at {}", self.path)
    }
}
impl Actionable for FileButton {
    fn execute(&self) -> String {
        format!("Opening file: {}", self.path)
    }
}

struct NetworkButton { 
    endpoint: String
}
impl Display for NetworkButton {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Network endpoint {}", self.endpoint)
    }
}
impl Actionable for NetworkButton {
    fn execute(&self) -> String {
        format!("Connecting to: {}", self.endpoint)
    }
}

fn main() {
    let file_btn = FileButton { path: "/usr/share/config.xml".to_string() };
    let net_btn = NetworkButton { endpoint: "api.example.com:8080".to_string() };

    println!("Available buttons:n{}", file_btn);
    println!("Available buttons:n{}", net_btn);

    let actions: Vec<Box<dyn Actionable>> = vec![Box::new(file_btn), Box::new(net_btn)];

    for action in actions {
        println!("nExecuting action...");
        println!("Result: {}", action.execute());
    }
}

use std::collections::HashMap;
use std::sync::Arc;

#[derive(Copy, Clone)]
struct Position { 
    x: f32,
    y: f32,
}

trait Movable: Send + Sync {
    fn get_id(&self) -> u64;
    fn report_position(&self) -> Position;
    fn calculate_new_path(&self, target: Position) -> Vec<Position>;
}

struct Tank { 
    unit_id: u64,
    current_pos: Position,
}
impl Movable for Tank {
    fn get_id(&self) -> u64 { self.unit_id }
    fn report_position(&self) -> Position { self.current_pos }
    fn calculate_new_path(&self, _target: Position) -> Vec<Position> { vec![] }
}

struct Scout {
    unit_id: u64,
    current_pos: Position,
}
impl Movable for Scout {
    fn get_id(&self) -> u64 { self.unit_id }
    fn report_position(&self) -> Position { self.current_pos }
    fn calculate_new_path(&self, _target: Position) -> Vec<Position> { vec![] }
}

fn process_movement(units: &HashMap<u64, Arc<dyn Movable>>, target: Position) -> HashMap<u64, Position> {
    let mut reports = HashMap::new();
    for unit in units.values() {
        reports.insert(unit.get_id(), unit.report_position());
    }
    reports
}

fn main() {
    let tank1: Arc<dyn Movable> = Arc::new(Tank { unit_id: 101, current_pos: Position { x: 0.0, y: 0.0 } });
    let scout1: Arc<dyn Movable> = Arc::new(Scout { unit_id: 201, current_pos: Position { x: 1.0, y: 2.0 } });

    let mut units: HashMap<u64, Arc<dyn Movable>> = HashMap::new();
    units.insert(tank1.get_id(), tank1);
    units.insert(scout1.get_id(), scout1);

    let target = Position { x: 5.0, y: 5.0 };
    let final_reports = process_movement(&units, target);

    println!("Unit movement reports:");
    for (id, pos) in &final_reports { 
        println!("ID {}: ({:.1}, {:.1})", id, pos.x, pos.y);
    }
}

use std::error::Error;

trait Processable {
    fn dimensions(&self) -> (usize, usize);
    fn apply_transformation(&self, transform: &Matrix) -> Result<Matrix, Box<dyn Error>>;
}

struct Matrix { 
    data: Vec<f64>,
    rows: usize,
    cols: usize
}

impl Matrix {
    fn new(data: Vec<f64>, rows: usize, cols: usize) -> Self {
        Matrix { data, rows, cols }
    }
    fn dimensions(&self) -> (usize, usize) {
        (self.rows, self.cols)
    }
}

struct SensorReading { 
    matrix_data: Vec<f64>,
    num_rows: usize,
    num_cols: usize
}

impl Processable for SensorReading {
    fn dimensions(&self) -> (usize, usize) {
        (self.num_rows, self.num_cols)
    }
    fn apply_transformation(&self, transform: &Matrix) -> Result<Matrix, Box<dyn Error>> {
        if self.dimensions() != transform.dimensions() {
            return Err(format!("Dimension mismatch for transformation").into());
        }
        let result_data = vec![0.0; self.matrix_data.len()];
        Ok(Matrix::new(result_data, self.num_rows, self.num_cols)) 
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let reading = SensorReading { 
        matrix_data: vec![1.0, 2.0], 
        num_rows: 1,
        num_cols: 2
    };
    let transform = Matrix::new(vec![3.0, 4.0], 1, 2);

    if let Ok(transformed) = reading.apply_transformation(&transform) {
        println!("Successfully processed data with dimensions: ({}, {}).", transformed.rows, transformed.cols);
    } else {
        eprintln!("Failed to process data.");
    }
    Ok(())
}

use std::io::{self, Write};

trait DataProcessor {
    fn process_handshake(&mut self, input: &[u8]) -> io::Result<Vec<u8>>;
}

struct TlsV13CipherProcessor {
    key_material: [u8; 32],
}

impl DataProcessor for TlsV13CipherProcessor {
    fn process_handshake(&mut self, input: &[u8]) -> io::Result<Vec<u8>> {
        let mut output = Vec::with_capacity(input.len() + 16);
        output.extend_from_slice(input);
        output.push(0xDE);
        output.write_all(&self.key_material).map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
        Ok(output)
    }
}

struct PlainTextEchoProcessor;

impl DataProcessor for PlainTextEchoProcessor {
    fn process_handshake(&mut self, input: &[u8]) -> io::Result<Vec<u8>> {
        let mut output = Vec::with_capacity(input.len());
        output.extend_from_slice(input);
        Ok(output)
    }
}

fn main() -> io::Result<()> {
    let raw_data = b"ClientHelloMessage";

    let mut cipher_processor = TlsV13CipherProcessor { key_material: [0xAA; 32] };
    let mut echo_processor = PlainTextEchoProcessor;

    let processed_cipher = cipher_processor.process_handshake(raw_data)?;
    println!("Cipher Processed Output Length: {}", processed_cipher.len());

    let processed_echo = echo_processor.process_handshake(raw_data)?;
    println!("Echo Processed Output Length: {}", processed_echo.len());

    let mut buffer = Vec::new();
    buffer.write_all(&processed_cipher)?;
    io::stdout().write_all(format!("
Finished processing handshake data.
").as_bytes())?;

    Ok(())
}
